const response = $input.first().json;
const responseData = JSON.stringify(response).toLowerCase();
if (responseData.includes('<!doctype html') || responseData.includes('<html') || responseData.includes('ngrok') || responseData.includes('tunnel not found')) {
  throw new Error('Transcription service unreachable. The ngrok tunnel appears dead/expired. Restart Colab and update COLAB_NGROK_URL. File: ' + $('Watch Incoming Audio').item.json.name);
}
const statusCode = response.statusCode || response.status_code || response.code;
if (statusCode && statusCode >= 400) {
  throw new Error('Transcription HTTP error ' + statusCode + '. Check if Colab is running. File: ' + $('Watch Incoming Audio').item.json.name);
}
if (response.error) {
  throw new Error('Transcription error: ' + (response.error.message || response.error) + '. File: ' + $('Watch Incoming Audio').item.json.name);
}
const transcript = response.transcript || '';
if (!transcript || transcript.trim().length < 20) {
  throw new Error('Transcript empty or too short. Colab Flask may not be running. File: ' + $('Watch Incoming Audio').item.json.name);
}
return [{
  json: {
    transcript: transcript.trim(),
    audioFileId: $('Watch Incoming Audio').item.json.id,
    audioFileName: $('Watch Incoming Audio').item.json.name,
    timestamp: new Date().toISOString()
  }
}];

// Parse GPT response and normalize to plain string arrays
const raw = $input.first().json?.message?.content
  || $input.first().json?.choices?.[0]?.message?.content
  || $input.first().json?.content
  || '';

// Strip markdown code fences if GPT wraps output
let cleaned = raw.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```json?\n?/, '').replace(/\n?```$/, '').trim();
}

if (!cleaned) {
  throw new Error('GPT returned an empty response.');
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('GPT returned malformed JSON. Raw output: ' + raw.substring(0, 300));
}

// Robust normalization: extract strings even if keys are slightly different
function normalizeToStrings(data, fallbackKey) {
  let arr = data[fallbackKey];

  // If exact key doesn't exist, try to find an array property that might be it
  if (!Array.isArray(arr)) {
    const arrays = Object.entries(data).filter(([k, v]) => Array.isArray(v));
    if (arrays.length > 0) {
       arr = arrays[0][1];
    } else {
       return [];
    }
  }

  return arr.map(item => {
    if (typeof item === 'string') return item;
    if (typeof item === 'object' && item !== null) {
      const firstStr = Object.values(item).find(v => typeof v === 'string');
      return firstStr || JSON.stringify(item);
    }
    return String(item);
  });
}

const linkedinposts = normalizeToStrings(parsed, 'linkedinposts');
const twitterposts = normalizeToStrings(parsed, 'twitterposts');
const hooks = normalizeToStrings(parsed, 'hooks');

// Only throw if absolutely nothing was found
if (linkedinposts.length === 0 && twitterposts.length === 0 && hooks.length === 0) {
  throw new Error('Could not find any content arrays in GPT response: ' + cleaned.substring(0, 200));
}

return [{
  json: {
    linkedinposts,
    twitterposts,
    hooks,
    transcript: $('Store Transcript Data').item.json.transcript,
    audioFileId: $('Store Transcript Data').item.json.audioFileId,
    timestamp: $('Store Transcript Data').item.json.timestamp
  }
}];

// ============================================================
// CONTENT ALCHEMIST â€” CENTRAL CONFIG
// Only thing to update manually: COLAB_NGROK_URL
// (paste new URL each time Colab restarts)
// ============================================================
return [{
  json: {
    COLAB_NGROK_URL: "PASTE_YOUR_NGROK_URL_HERE",
    TELEGRAM_CHAT_ID: "REPLACE_WITH_YOUR_CHAT_ID",
    INCOMING_AUDIO_FOLDER_ID: "REPLACE_WITH_YOUR_FOLDER_ID",
    TRANSCRIPT_FOLDER_ID: "REPLACE_WITH_YOUR_FOLDER_ID",
    LINKEDIN_POSTS_FOLDER_ID: "REPLACE_WITH_YOUR_FOLDER_ID",
    TWITTER_POSTS_FOLDER_ID: "REPLACE_WITH_YOUR_FOLDER_ID",
    HOOKS_FOLDER_ID: "REPLACE_WITH_YOUR_FOLDER_ID",
    POST_IMAGES_FOLDER_ID: "REPLACE_WITH_YOUR_FOLDER_ID",
    ARCHIVE_FOLDER_ID: "REPLACE_WITH_YOUR_FOLDER_ID",
    SHEETS_SPREADSHEET_ID: "REPLACE_WITH_YOUR_SPREADSHEET_ID"
  }
}];

